query:
-- change_logs: RPC'ler doğrudan yazmaz; audit tetikleyicilerde. Aktör: last_edited_by (users: + last_audit_tenant_id).
-- Önce şema genişletmesi

ALTER TABLE public.stage_metrics ADD COLUMN IF NOT EXISTS last_edited_by text;
ALTER TABLE public.mismatched_share_acknowledgments ADD COLUMN IF NOT EXISTS last_edited_by text;
ALTER TABLE public.users ADD COLUMN IF NOT EXISTS last_edited_by text;
ALTER TABLE public.users ADD COLUMN IF NOT EXISTS last_audit_tenant_id uuid REFERENCES public.tenants(id);
ALTER TABLE public.user_tenants ADD COLUMN IF NOT EXISTS last_edited_by text;

-- ─── next ───

-- Hisse uyumsuzluğu kaydı INSERT/UPDATE/DELETE → change_logs (RPC doğrudan yazmaz)
-- UPDATE: yalnızca onay bilgisi değişince log (revoke öncesi sadece last_edited_by ise yazma)
-- DELETE: clear_mismatched_ack tetikleyicisi app.skip_mismatch_delete_log = '1' ile log bastırır

CREATE OR REPLACE FUNCTION public.log_mismatched_share_ack_changes()
RETURNS trigger
LANGUAGE plpgsql
AS $BODY$
DECLARE
  v_no int2;
  v_year int2;
  v_owner text;
BEGIN
  IF TG_OP = 'DELETE' THEN
    IF NULLIF(btrim(COALESCE(current_setting('app.skip_mismatch_delete_log', true), '')), '') = '1' THEN
      RETURN OLD;
    END IF;

    SELECT sa.sacrifice_no, sa.sacrifice_year
    INTO v_no, v_year
    FROM sacrifice_animals sa
    WHERE sa.sacrifice_id = OLD.sacrifice_id;

    v_owner := COALESCE(NULLIF(btrim(OLD.last_edited_by), ''), OLD.acknowledged_by);

    INSERT INTO public.change_logs (
      table_name,
      row_id,
      change_type,
      description,
      change_owner,
      tenant_id,
      sacrifice_year
    )
    VALUES (
      'Hisse Uyumsuzluğu',
      v_no::text,
      'Güncelleme',
      'Hisse uyumsuzluğu onayı kaldırıldı; bu kurbanlık listesinde yeniden uyarı gösterebilir. Kurban sıra no: ' || v_no::text || '.',
      v_owner,
      OLD.tenant_id,
      v_year
    );

    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF NEW.acknowledged_by IS NOT DISTINCT FROM OLD.acknowledged_by
       AND NEW.acknowledged_at IS NOT DISTINCT FROM OLD.acknowledged_at THEN
      RETURN NEW;
    END IF;
  END IF;

  IF TG_OP IN ('INSERT', 'UPDATE') THEN
    SELECT sa.sacrifice_no, sa.sacrifice_year
    INTO v_no, v_year
    FROM sacrifice_animals sa
    WHERE sa.sacrifice_id = NEW.sacrifice_id;

    v_owner := COALESCE(NULLIF(btrim(NEW.last_edited_by), ''), NEW.acknowledged_by);

    INSERT INTO public.change_logs (
      table_name,
      row_id,
      change_type,
      description,
      change_owner,
      tenant_id,
      sacrifice_year
    )
    VALUES (
      'Hisse Uyumsuzluğu',
      v_no::text,
      'Güncelleme',
      'Bu kurbanlıkta toplam hisse sayısı 7 değil; yönetici ekranda «Tamam, uyumsuzluğu biliyorum» ile uyarıyı onayladı. Kurban sıra no: ' || v_no::text || '.',
      v_owner,
      NEW.tenant_id,
      v_year
    );

    RETURN NEW;
  END IF;

  RETURN NULL;
END;
$BODY$;

DROP TRIGGER IF EXISTS trigger_mismatched_share_ack_changes ON public.mismatched_share_acknowledgments;

CREATE TRIGGER trigger_mismatched_share_ack_changes
  AFTER INSERT OR UPDATE OR DELETE ON public.mismatched_share_acknowledgments
  FOR EACH ROW
  EXECUTE FUNCTION public.log_mismatched_share_ack_changes();

-- ─── next ───

-- stage_metrics: current_sacrifice_number değişince change_logs (Türkçe, change_owner = last_edited_by veya otomatik etiket)

CREATE OR REPLACE FUNCTION public.log_stage_metrics_changes()
RETURNS trigger
LANGUAGE plpgsql
AS $BODY$
DECLARE
  v_owner text;
  v_stage_label text;
BEGIN
  IF TG_OP <> 'UPDATE' THEN
    RETURN NEW;
  END IF;

  IF NEW.current_sacrifice_number IS NOT DISTINCT FROM OLD.current_sacrifice_number THEN
    RETURN NEW;
  END IF;

  v_owner := COALESCE(NULLIF(btrim(NEW.last_edited_by), ''), 'Sistem (aşama otomatiği)');

  v_stage_label := CASE NEW.stage
    WHEN 'slaughter_stage' THEN 'Kesim'
    WHEN 'butcher_stage' THEN 'Parçalama'
    WHEN 'delivery_stage' THEN 'Teslimat'
    ELSE NEW.stage
  END;

  INSERT INTO public.change_logs (
    table_name,
    row_id,
    column_name,
    old_value,
    new_value,
    change_type,
    description,
    change_owner,
    tenant_id
  )
  VALUES (
    'Aşama Metrikleri',
    NEW.stage,
    'Güncel kurban sırası (takip)',
    OLD.current_sacrifice_number::text,
    NEW.current_sacrifice_number::text,
    'Güncelleme',
    'Takip ekranında «' || v_stage_label || '» aşaması için gösterilen «şu an işlenen kurban sıra numarası» güncellendi: '
      || COALESCE(OLD.current_sacrifice_number::text, '—') || ' → ' || COALESCE(NEW.current_sacrifice_number::text, '—') || '.',
    v_owner,
    NEW.tenant_id
  );

  RETURN NEW;
END;
$BODY$;

DROP TRIGGER IF EXISTS trigger_stage_metrics_changes ON public.stage_metrics;

CREATE TRIGGER trigger_stage_metrics_changes
  AFTER UPDATE ON public.stage_metrics
  FOR EACH ROW
  EXECUTE FUNCTION public.log_stage_metrics_changes();

-- ─── next ───

-- users → change_logs (yalnızca tetikleyici). change_owner = last_edited_by (+ yedek tenant: last_audit_tenant_id)

CREATE OR REPLACE FUNCTION public.log_users_changes()
RETURNS trigger
LANGUAGE plpgsql
AS $BODY$
DECLARE
  v_owner text;
  v_tenant uuid;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_owner := COALESCE(NULLIF(btrim(NEW.last_edited_by), ''), 'Anonim Kullanıcı');
    -- İlk satır: user_tenants henüz yok; RPC last_audit_tenant_id doldurur
    v_tenant := COALESCE(
      NEW.last_audit_tenant_id,
      (SELECT ut.tenant_id FROM public.user_tenants ut WHERE ut.user_id = NEW.id ORDER BY ut.tenant_id LIMIT 1)
    );
    IF v_tenant IS NULL THEN
      RETURN NEW;
    END IF;
    INSERT INTO public.change_logs (
      table_name, row_id, change_type, description, change_owner, tenant_id
    )
    VALUES (
      'Kullanıcılar',
      NEW.id::text,
      'Ekleme',
      'Sisteme yeni kullanıcı kaydı eklendi. Giriş e-postası: ' || NEW.email || '.',
      v_owner,
      v_tenant
    );
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    v_owner := COALESCE(NULLIF(btrim(NEW.last_edited_by), ''), NULLIF(btrim(OLD.last_edited_by), ''), 'Anonim Kullanıcı');
    v_tenant := COALESCE(
      NEW.last_audit_tenant_id,
      OLD.last_audit_tenant_id,
      (SELECT ut.tenant_id FROM public.user_tenants ut WHERE ut.user_id = NEW.id ORDER BY ut.tenant_id LIMIT 1)
    );
    IF v_tenant IS NULL THEN
      RETURN NEW;
    END IF;

    IF NEW.name IS DISTINCT FROM OLD.name THEN
      INSERT INTO public.change_logs (table_name, row_id, column_name, old_value, new_value, change_type, description, change_owner, tenant_id)
      VALUES (
        'Kullanıcılar', NEW.id::text, 'Ad', OLD.name, NEW.name, 'Güncelleme',
        'Panelde görünen kullanıcı adı değişti: «' || COALESCE(OLD.name, '—') || '» → «' || COALESCE(NEW.name, '—') || '».',
        v_owner, v_tenant
      );
    END IF;

    IF NEW.image IS DISTINCT FROM OLD.image THEN
      INSERT INTO public.change_logs (table_name, row_id, column_name, old_value, new_value, change_type, description, change_owner, tenant_id)
      VALUES (
        'Kullanıcılar', NEW.id::text, 'Profil görseli', OLD.image, NEW.image, 'Güncelleme',
        'Profil fotoğrafı veya avatar adresi değiştirildi.',
        v_owner, v_tenant
      );
    END IF;

    IF NEW.role IS DISTINCT FROM OLD.role THEN
      INSERT INTO public.change_logs (table_name, row_id, column_name, old_value, new_value, change_type, description, change_owner, tenant_id)
      VALUES (
        'Kullanıcılar', NEW.id::text, 'Rol', OLD.role::text, NEW.role::text, 'Güncelleme',
        'Sistem rolü (yetki seviyesi) güncellendi: '
          || CASE OLD.role::text WHEN 'editor' THEN 'Editör' WHEN 'admin' THEN 'Yönetici' WHEN 'super_admin' THEN 'Süper yönetici' ELSE COALESCE(OLD.role::text, '—') END
          || ' → '
          || CASE NEW.role::text WHEN 'editor' THEN 'Editör' WHEN 'admin' THEN 'Yönetici' WHEN 'super_admin' THEN 'Süper yönetici' ELSE COALESCE(NEW.role::text, '—') END
          || '. Menü ve işlem yetkilerini etkiler.',
        v_owner, v_tenant
      );
    END IF;

    IF NEW.email IS DISTINCT FROM OLD.email THEN
      INSERT INTO public.change_logs (table_name, row_id, column_name, old_value, new_value, change_type, description, change_owner, tenant_id)
      VALUES (
        'Kullanıcılar', NEW.id::text, 'E-posta', OLD.email, NEW.email, 'Güncelleme',
        'Giriş e-postası değiştirildi: ' || COALESCE(OLD.email, '—') || ' → ' || COALESCE(NEW.email, '—') || '.',
        v_owner, v_tenant
      );
    END IF;

    IF NEW.status IS DISTINCT FROM OLD.status THEN
      INSERT INTO public.change_logs (table_name, row_id, column_name, old_value, new_value, change_type, description, change_owner, tenant_id)
      VALUES (
        'Kullanıcılar', NEW.id::text, 'Durum', OLD.status::text, NEW.status::text, 'Güncelleme',
        'Hesap durumu değişti: '
          || CASE OLD.status::text WHEN 'pending' THEN 'Onay bekliyor' WHEN 'approved' THEN 'Onaylı' WHEN 'rejected' THEN 'Reddedildi' ELSE COALESCE(OLD.status::text, '—') END
          || ' → '
          || CASE NEW.status::text WHEN 'pending' THEN 'Onay bekliyor' WHEN 'approved' THEN 'Onaylı' WHEN 'rejected' THEN 'Reddedildi' ELSE COALESCE(NEW.status::text, '—') END
          || '.',
        v_owner, v_tenant
      );
    END IF;

    RETURN NEW;
  END IF;

  IF TG_OP = 'DELETE' THEN
    v_owner := COALESCE(NULLIF(btrim(OLD.last_edited_by), ''), 'Anonim Kullanıcı');
    v_tenant := COALESCE(
      OLD.last_audit_tenant_id,
      (SELECT ut.tenant_id FROM public.user_tenants ut WHERE ut.user_id = OLD.id ORDER BY ut.tenant_id LIMIT 1)
    );
    IF v_tenant IS NOT NULL THEN
      INSERT INTO public.change_logs (table_name, row_id, change_type, description, change_owner, tenant_id)
      VALUES (
        'Kullanıcılar',
        OLD.id::text,
        'Silme',
        'Kullanıcı hesabı tamamen silindi. E-posta: ' || OLD.email || '.',
        v_owner,
        v_tenant
      );
    END IF;
    RETURN OLD;
  END IF;

  RETURN NULL;
END;
$BODY$;

DROP TRIGGER IF EXISTS trigger_users_changes ON public.users;

CREATE TRIGGER trigger_users_changes
  AFTER INSERT OR UPDATE OR DELETE ON public.users
  FOR EACH ROW
  EXECUTE FUNCTION public.log_users_changes();

-- ─── next ───

-- user_tenants: çoklu tenant onayı + org içi onay iptali → change_logs

CREATE OR REPLACE FUNCTION public.log_user_tenants_changes()
RETURNS trigger
LANGUAGE plpgsql
AS $BODY$
DECLARE
  v_owner text;
  v_cnt int;
BEGIN
  IF TG_OP = 'INSERT' THEN
    IF NEW.approved_at IS NULL THEN
      RETURN NEW;
    END IF;
    SELECT COUNT(*)::int INTO v_cnt FROM public.user_tenants ut WHERE ut.user_id = NEW.user_id;
    -- Yalnızca ikinci (ilk ek) onaylı bağlantı: 3. tenant eklemelerinde tekrarlamayı önle
    IF v_cnt <> 2 THEN
      RETURN NEW;
    END IF;
    v_owner := COALESCE(NULLIF(btrim(NEW.last_edited_by), ''), 'Anonim Kullanıcı');
    INSERT INTO public.change_logs (table_name, row_id, change_type, description, change_owner, tenant_id)
    VALUES (
      'Kullanıcılar',
      NEW.user_id::text,
      'Güncelleme',
      'Kullanıcı ikinci bir organizasyonda da onaylı üye yapıldı (aynı hesap, çoklu site erişimi).',
      v_owner,
      NEW.tenant_id
    );
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF OLD.approved_at IS NOT NULL AND NEW.approved_at IS NULL THEN
      v_owner := COALESCE(NULLIF(btrim(NEW.last_edited_by), ''), NULLIF(btrim(OLD.last_edited_by), ''), 'Anonim Kullanıcı');
      INSERT INTO public.change_logs (table_name, row_id, change_type, description, change_owner, tenant_id)
      VALUES (
        'Kullanıcılar',
        NEW.user_id::text,
        'Güncelleme',
        'Bu organizasyonda kullanıcının «onaylı üye» kaydı kaldırıldı; tekrar onaylanması gerekebilir.',
        v_owner,
        NEW.tenant_id
      );
    ELSIF OLD.approved_at IS NULL AND NEW.approved_at IS NOT NULL THEN
      -- INSERT ... ON CONFLICT DO UPDATE onay: ikinci onaylı org (tam 2 onaylı bağlantı)
      SELECT COUNT(*)::int INTO v_cnt FROM public.user_tenants ut
      WHERE ut.user_id = NEW.user_id AND ut.approved_at IS NOT NULL;
      IF v_cnt = 2 THEN
        v_owner := COALESCE(NULLIF(btrim(NEW.last_edited_by), ''), 'Anonim Kullanıcı');
        INSERT INTO public.change_logs (table_name, row_id, change_type, description, change_owner, tenant_id)
        VALUES (
          'Kullanıcılar',
          NEW.user_id::text,
          'Güncelleme',
          'Kullanıcı ikinci bir organizasyonda da onaylı üye yapıldı (aynı hesap, çoklu site erişimi).',
          v_owner,
          NEW.tenant_id
        );
      END IF;
    END IF;
    RETURN NEW;
  END IF;

  RETURN NULL;
END;
$BODY$;

DROP TRIGGER IF EXISTS trigger_user_tenants_changes ON public.user_tenants;

CREATE TRIGGER trigger_user_tenants_changes
  AFTER INSERT OR UPDATE ON public.user_tenants
  FOR EACH ROW
  EXECUTE FUNCTION public.log_user_tenants_changes();

